// Approval links use GET with query params:
// ?pr_id=PR-001&decision=approved&approver=manager@company.com&reason=optional+text
const query = $input.first().json.query ?? $input.first().json;

const pr_id = query.pr_id;
const decision = query.decision;
const approver = query.approver;
const reason = query.reason ?? null;

if (!pr_id) throw new Error('Missing pr_id');
if (!['approved', 'rejected'].includes(decision)) throw new Error('Invalid decision value: ' + decision);

return [{
  json: {
    pr_id,
    decision,
    approver_email: approver,
    reason,
    responded_at: new Date().toISOString()
  }
}];

// LangGraph returns requester details after processing the approval
const agentResponse = $input.first().json;
return [{
  json: {
    pr_id: agentResponse.pr_id,
    requester_email: agentResponse.requester_email,
    requester_name: agentResponse.requester_name,
    po_number: agentResponse.po_number,
    amount: agentResponse.amount,
    currency: agentResponse.currency,
    description: agentResponse.description
  }
}];

const agentResponse = $input.first().json;
return [{
  json: {
    pr_id: agentResponse.pr_id,
    requester_email: agentResponse.requester_email,
    requester_name: agentResponse.requester_name,
    amount: agentResponse.amount,
    currency: agentResponse.currency,
    description: agentResponse.description,
    rejection_reason: agentResponse.rejection_reason ?? 'No reason provided'
  }
}];
